<?php namespace App\Http\Controllers\Expense;
use App\Http\Controllers\Controller; use App\Models\Expense; use App\Models\Ecommerce\StoreLocation; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Storage; use Illuminate\Support\Str; use Illuminate\Validation\Rule;
class ExpenseController extends Controller { public function index(Request $r){$q=$this->filtered($r)->with(['branch','category','creator']);$total=(clone $q)->sum('amount');return $this->respond(['items'=>$q->orderByDesc('expense_date')->orderByDesc('id')->paginate($r->integer('per_page',15)),'total'=>(string)$total]);} public function show(Expense $expense){return $this->respond($expense->load(['branch','category','creator']));} public function store(Request $r){$data=$this->data($r);$data['store_location_id']=$data['store_location_id']??StoreLocation::where(['is_active'=>true,'is_default'=>true])->value('id');if(!$data['store_location_id'])return $this->respondError('An active default branch is required.',422);$data['created_by']=$r->user()->id;$data['updated_by']=$r->user()->id;return DB::transaction(function()use($data,$r){$data['expense_no']=$this->number($data['expense_date']);if($r->hasFile('receipt'))$data['receipt_path']=$this->upload($r);$e=Expense::create($data);return $this->respond($e->load(['branch','category','creator']),'Expense created.',true,201);});} public function update(Request $r,Expense $expense){$data=$this->data($r);$data['updated_by']=$r->user()->id;if($r->hasFile('receipt')){$new=$this->upload($r);if($expense->receipt_path)Storage::disk('public')->delete($expense->receipt_path);$data['receipt_path']=$new;} $expense->update($data);return $this->respond($expense->fresh()->load(['branch','category','creator']),'Expense updated.');} public function destroy(Expense $expense){$expense->delete();return $this->respond(null,'Expense deleted.');} public function export(Request $r){$rows=$this->filtered($r)->with(['branch','category','creator'])->orderBy('expense_date')->get();return response()->streamDownload(function()use($rows){$o=fopen('php://output','w');fputcsv($o,['Expense No','Expense Date','Branch','Title','Category','Amount','Remark','Created By','Created At']);foreach($rows as $e)fputcsv($o,[$e->expense_no,$e->expense_date->format('Y-m-d'),$e->branch?->name,$e->title,$e->category?->name,$e->amount,$e->remark,$e->creator?->name,$e->created_at]);fclose($o);},'expenses.csv',['Content-Type'=>'text/csv']);} private function filtered(Request $r){return Expense::query()->when($r->month,fn($q,$m)=>$q->whereBetween('expense_date',["$m-01",now()->parse("$m-01")->endOfMonth()->toDateString()]))->when($r->date_from,fn($q,$v)=>$q->whereDate('expense_date','>=',$v))->when($r->date_to,fn($q,$v)=>$q->whereDate('expense_date','<=',$v))->when($r->branch_id,fn($q,$v)=>$q->where('store_location_id',$v))->when($r->expense_category_id,fn($q,$v)=>$q->where('expense_category_id',$v))->when($r->search,function($q,$s){$q->where(fn($x)=>$x->where('expense_no','like',"%$s%")->orWhere('title','like',"%$s%")->orWhere('remark','like',"%$s%")->orWhereHas('category',fn($c)=>$c->where('name','like',"%$s%")));});} private function data(Request $r){return $r->validate(['store_location_id'=>['nullable','integer',Rule::exists('store_locations','id')->where('is_active',true)],'expense_category_id'=>['required','integer',Rule::exists('expense_categories','id')->where('is_active',true)],'expense_date'=>['required','date'],'title'=>['required','string','max:255'],'amount'=>['required','decimal:0,2','gt:0'],'remark'=>['nullable','string'],'receipt'=>['nullable','file','mimes:jpeg,jpg,png,webp,pdf','max:5120']]);} private function number($date){$prefix='EXP-'.now()->parse($date)->format('Ym').'-';$last=Expense::withTrashed()->where('expense_no','like',$prefix.'%')->lockForUpdate()->orderByDesc('id')->value('expense_no');return $prefix.str_pad(((int)substr((string)$last,-5))+1,5,'0',STR_PAD_LEFT);} private function upload(Request $r){$f=$r->file('receipt');return $f->storeAs('expense-receipts',Str::uuid().'.'.$f->extension(),'public');}}
